import type { PopupsContextData } from ':helpers/popupsContext';
import { PopupsContext } from ':helpers/popupsContext';
import type { FC } from 'react';
import { createContext, useContext, useLayoutEffect, useMemo } from 'react';
import ReactDom from 'react-dom';

import type { ModalProps } from './Modal.types';

export const ModalContext = createContext<{
	applicationElementId?: string;
	modalElementID?: string;
}>({});

export const Modal: FC<ModalProps> = ({ open = false, className, applicationRootElement, children, ...rest }) => {
	let bodyOverflowValue = 'unset';
	const { applicationElementId: contextAppElementID, modalElementID } = useContext(ModalContext);
	const { applicationElementID: baseContextAppElementID, rootElement } = useContext<PopupsContextData>(PopupsContext);

	const appElementID = applicationRootElement || contextAppElementID || baseContextAppElementID || 'root';

	const target = rootElement || document.getElementById(appElementID);

	if (!target) {
		throw new Error(`Application root element with ID "${appElementID}" not found`);
	}

	const div = useMemo(() => {
		const element = document.createElement('div');
		element.className += className;
		element.ariaModal = 'true';
		element.role = 'dialog';

		element.dataset.testid = 'Modal';

		for (const [key, value] of Object.entries(rest)) {
			element.setAttribute(key, value as string);
		}

		if (modalElementID) {
			element.id += modalElementID;
		}

		return element;
		// rest намеренно не указан среди зависимостей, т.к приводит к неконтролируемым ререндерам
		// при этом присвоить эти параметры важно, а их изменение при открытом Modal маловероятно
		// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [className, modalElementID]);

	useLayoutEffect(() => {
		if (open) {
			bodyOverflowValue = document.body.style.overflow;
			document.body.style.overflow = 'hidden';
			target?.append(div);
			return () => {
				target?.removeChild(div);
				document.body.style.overflow = bodyOverflowValue;
			};
		}
		return void 0;
	}, [open, target, div]);

	if (!open) {
		return null;
	}

	return ReactDom.createPortal(children, div);
};
